VALUES
  ('police-8b7f1efc-moex-00157', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '關於憲法第7條男女平等，司法院大法官曾作過的違憲宣告解釋，不包括下列何者？', '["舊民法第 1089 條關於父母對於未成年子女權利之行使意思不一致時，由父行使之規定部 分，違憲", "舊民法第1002條「妻以夫之住所為住所」之規定，違憲", "民法夫妻財產制修正後對修正前已發生之夫妻聯合財產，規定仍由夫繼續享有之部分，違憲", "陸軍官校基於其歷史傳統而以性別為錄取學生之標準，違憲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00158', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '地價稅法關於免徵土地增值稅之規定，僅就依都市計畫法指定之公共設施保留地免徵其土地 增值稅，而非都市土地經編定為交通用地且依法核定為公共用地者，則不予免徵。司法院大 法官解釋認定上開規定違反平等權之理由為：', '["此差別待遇之手段與立法目的之達成間欠缺合理關聯性", "此差別待遇未符合比例原則", "以與事物本質無關之要素，作為差別待遇之基準", "未將與事物本質有關聯之要素，列為差別待遇之基準"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00159', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '依司法院大法官解釋，有關憲法第15條之生存權，下列敘述何者錯誤？', '["憲法第15條之生存權保障範圍包含生命權", "大法官解釋曾認墮胎罪違憲", "生存權之主要目的在保障國民之最低生活水準", "大法官解釋曾認死刑合憲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00160', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '憲法本文有關憲法基本權利之規定 ，下列何者之規定內容最為具體？', '["憲法第14條之集會、結社自由", "憲法第11條之言論、講學、著作及出版自由", "憲法第8條之人身自由", "憲法第7條之平等權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00161', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '下列有關訴訟權之敘述，何者錯誤？', '["憲法保障人民訴訟權，係指人民於其權利或法律上利益遭受侵害時，有請求法院救濟之權利", "此乃基於有權利即有救濟之憲法原理", "訴訟權之具體內容，應由立法機關制定法院組織與訴訟程序有關之法律，始得實現", "立法機關得因身分之不同，而予以限制，不受憲法第23條之拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00162', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '依司法院大法官解釋意旨，關於國家賠償之憲法保障內涵，下列敘述何者錯誤？', '["如果沒有法律規定，人民尚不得依照憲法第24條，直接行使國家賠償請求權", "就公務員怠於執行職務之國家賠償責任，不以人民應先請求公務員執行而怠於執行為必要", "就公務員執行職務之國家賠償責任，立法者對於是否採無過失責任享有立法形成自由", "法律規範目的如有保障人民生命、身體及財產等法益之意旨時，即可直接認定被害人得向 國家請求損害賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00163', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '受國民教育以外教育之權利，係下列何憲法條文之保障範圍？', '["第21條受國民教育之權利", "第22條之其他自由或權利", "第159條國民受教育之機會平等", "第163條國家應注重各地區教育之均衡發展"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00164', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '關於基本權利之第三人效力，下列敘述何者正確？', '["意指國家不得干預人民間的契約自由，以保障私法自治", "意指基本權利拘束行政、立法、司法各部門", "意指透過解釋私法上的一般條款與不確定法律概念，使基本權利得直接適用於私人關係", "有直接適用、間接適用和無拘束力等不同見解"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00165', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '某國營事業的工廠排放工業廢氣及廢水，導致居民因惡性腫瘤的死亡率明顯高於全國平均值 。下列敘述何者正確？', '["基本權不僅拘束國家公權力行為，也拘束行政私法行為", "國營事業的工廠排放廢水及廢氣，屬於公權力行為", "國營事業並非政府，故人民無法主張生存權受到侵害", "健康權非我國憲法所明文保障，故人民無法主張健康權受到侵害"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00166', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-15a7b19c', 'sub-police-8b7f1efc-01', NULL, 'single_choice', '依司法院釋字第688號解釋，立法者於制定法律時，創設一具有體系規範意義之法律原則時 ，除有基於重大公益之考量外，應受其原則拘束以維持法律體系之一貫性，是為體系之正義 。其後立法有違背此體系正義時，係違反下列何原則？', '["比例原則", "平等原則", "信賴保護原則", "誠信原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
